#include <bits/stdc++.h>
using namespace std;


int binary_search(int arr[], int size_arr, int target) {
    int left = 0, right = size_arr - 1;

    while(right >= left) {
        int mid = (left + right) / 2;
        if(arr[mid] == target) {
            return mid + 1;
        }
        else if(arr[mid] > target) {
            right = mid - 1;
        }
        else {
            left = mid + 1;
        }
    }

    return -1;
}

int main() {
    int t; cin >> t;
    while(t--) {
        int n; cin >> n;
        int x; cin >> x;
        int arr[n];
        for(int i = 0; i < n; i++) cin >> arr[i];

        cout << binary_search(arr, n, x) << "\n";
    } 
    return 0;
}

